  1→// Package namematch provides deterministic institution name matching.
  2→//
  3→// It loads all institutions and aliases from the database into in-memory maps
  4→// and resolves input names to unit_id values via a 3-tier lookup:
  5→//
  6→//  1. Exact lowercase match against institution_name
  7→//  2. Normalized match (diacritics stripped, punctuation removed, etc.)
  8→//  3. Builtin alias overrides for common external-source name variants
  9→//  4. DB alias match from search_base.institution_alias
 10→//
 11→// MatchByOPE6 and MatchByOPE8 provide direct lookups by OPE ID.
 12→package namematch
 13→
 14→import (
 15→	"context"
 16→	"fmt"
 17→	"strings"
 18→
 19→	"github.com/jackc/pgx/v5/pgxpool"
 20→)
 21→
 22→// Matcher holds in-memory lookup maps for deterministic name resolution.
 23→type Matcher struct {
 24→	exact      map[string]string // strings.ToLower(institution_name) → unit_id
 25→	normalized map[string]string // Normalize(institution_name) → unit_id
 26→	alias      map[string]string // strings.ToLower(db alias) → unit_id
 27→	ope6       map[string]string // ope6_id → unit_id
 28→	ope8       map[string]string // ope8_id → unit_id
 29→	unitIDs    map[string]bool   // set of all known unit_ids
 30→}
 31→
 32→// Load queries all institutions and aliases from the database and returns a
 33→// ready-to-use Matcher. The pool must be connected and the schema must be
 34→// populated.
 35→func Load(ctx context.Context, pool *pgxpool.Pool) (*Matcher, error) {
 36→	m := &Matcher{
 37→		exact:      make(map[string]string),
 38→		normalized: make(map[string]string),
 39→		alias:      make(map[string]string),
 40→		ope6:       make(map[string]string),
 41→		ope8:       make(map[string]string),
 42→		unitIDs:    make(map[string]bool),
 43→	}
 44→
 45→	if err := m.loadInstitutions(ctx, pool); err != nil {
 46→		return nil, fmt.Errorf("namematch: load institutions: %w", err)
 47→	}
 48→	if err := m.loadAliases(ctx, pool); err != nil {
 49→		return nil, fmt.Errorf("namematch: load aliases: %w", err)
 50→	}
 51→	return m, nil
 52→}
 53→
 54→func (m *Matcher) loadInstitutions(ctx context.Context, pool *pgxpool.Pool) error {
 55→	rows, err := pool.Query(ctx,
 56→		`SELECT unit_id, institution_name, ope6_id, ope8_id FROM search_base.institution`)
 57→	if err != nil {
 58→		return err
 59→	}
 60→	defer rows.Close()
 61→
 62→	for rows.Next() {
 63→		var unitID, name, ope6, ope8 string
 64→		if err := rows.Scan(&unitID, &name, &ope6, &ope8); err != nil {
 65→			return err
 66→		}
 67→		m.exact[strings.ToLower(name)] = unitID
 68→		m.normalized[Normalize(name)] = unitID
 69→		m.unitIDs[unitID] = true
 70→		if ope6 != "" {
 71→			m.ope6[ope6] = unitID
 72→		}
 73→		if ope8 != "" {
 74→			m.ope8[ope8] = unitID
 75→		}
 76→	}
 77→	return rows.Err()
 78→}
 79→
 80→func (m *Matcher) loadAliases(ctx context.Context, pool *pgxpool.Pool) error {
 81→	rows, err := pool.Query(ctx,
 82→		`SELECT unit_id, alias FROM search_base.institution_alias`)
 83→	if err != nil {
 84→		return err
 85→	}
 86→	defer rows.Close()
 87→
 88→	for rows.Next() {
 89→		var unitID, alias string
 90→		if err := rows.Scan(&unitID, &alias); err != nil {
 91→			return err
 92→		}
 93→		m.alias[strings.ToLower(alias)] = unitID
 94→	}
 95→	return rows.Err()
 96→}
 97→
 98→// Match resolves an institution name to its unit_id using a 3-tier lookup:
 99→//  1. Exact lowercase match
100→//  2. Normalized match
101→//  3. Builtin alias (normalized input → canonical name → normalized lookup)
102→//  4. DB alias (lowercase)
103→//
104→// Returns ("", false) if no match is found.
105→func (m *Matcher) Match(name string) (unitID string, ok bool) {
106→	// Tier 1: exact lowercase
107→	lower := strings.ToLower(name)
108→	if uid, found := m.exact[lower]; found {
109→		return uid, true
110→	}
111→
112→	// Tier 2: normalized
113→	nkey := Normalize(name)
114→	if uid, found := m.normalized[nkey]; found {
115→		return uid, true
116→	}
117→
118→	// Tier 3: builtin alias → normalize canonical name → normalized lookup
119→	if canonical, found := builtinAliases[nkey]; found {
120→		if uid, found := m.normalized[Normalize(canonical)]; found {
121→			return uid, true
122→		}
123→	}
124→
125→	// Tier 4: DB alias (lowercase)
126→	if uid, found := m.alias[lower]; found {
127→		return uid, true
128→	}
129→
130→	return "", false
131→}
132→
133→// MatchByOPE6 looks up an institution by its 6-digit OPE ID.
134→func (m *Matcher) MatchByOPE6(ope6 string) (unitID string, ok bool) {
135→	uid, found := m.ope6[ope6]
136→	return uid, found
137→}
138→
139→// MatchByOPE8 looks up an institution by its 8-digit OPE ID.
140→func (m *Matcher) MatchByOPE8(ope8 string) (unitID string, ok bool) {
141→	uid, found := m.ope8[ope8]
142→	return uid, found
143→}
144→
145→// MatchByIPEDS checks whether a unit_id (IPEDS UNITID) exists in the matcher.
146→// In the NCES schema, unit_id is the IPEDS UNITID, so this is a direct lookup.
147→func (m *Matcher) MatchByIPEDS(ipedsID string) (unitID string, ok bool) {
148→	if m.unitIDs[ipedsID] {
149→		return ipedsID, true
150→	}
151→	return "", false
152→}
153→
154→// AllNames returns all institution names known to the matcher.
155→func (m *Matcher) AllNames() []string {
156→	names := make([]string, 0, len(m.exact))
157→	for name := range m.exact {
158→		names = append(names, name)
159→	}
160→	return names
161→}
162→

  1→package csvutil
  2→
  3→import (
  4→	"strings"
  5→	"testing"
  6→)
  7→
  8→const csvData = `name,age,score,city
  9→Alice,30,9.5,New York
 10→Bob,25,8.1,
 11→Charlie,0,,Paris
 12→`
 13→
 14→const tsvData = "name\tage\tscore\n" +
 15→	"Alice\t30\t9.5\n" +
 16→	"Bob\t25\t8.1\n"
 17→
 18→const quotedCSV = `name,description,value
 19→Alice,"tall, blonde, and smart",42
 20→Bob,"says ""hello"" often",7
 21→Carol,"line1
 22→line2",99
 23→`
 24→
 25→const headerOnlyCSV = "name,age,score\n"
 26→
 27→func mustReader(t *testing.T, data string, opts ...Option) *Reader {
 28→	t.Helper()
 29→	r, err := NewReader(strings.NewReader(data), opts...)
 30→	if err != nil {
 31→		t.Fatalf("NewReader: %v", err)
 32→	}
 33→	return r
 34→}
 35→
 36→func collectRows(t *testing.T, r *Reader) []Row {
 37→	t.Helper()
 38→	var rows []Row
 39→	for {
 40→		row, ok, err := r.Next()
 41→		if err != nil {
 42→			t.Fatalf("Next: %v", err)
 43→		}
 44→		if !ok {
 45→			break
 46→		}
 47→		rows = append(rows, row)
 48→	}
 49→	return rows
 50→}
 51→
 52→// 1. Normal CSV parsing.
 53→func TestNormalCSV(t *testing.T) {
 54→	r := mustReader(t, csvData)
 55→	rows := collectRows(t, r)
 56→
 57→	if len(rows) != 3 {
 58→		t.Fatalf("want 3 rows, got %d", len(rows))
 59→	}
 60→
 61→	if got := rows[0].String("name"); got != "Alice" {
 62→		t.Errorf("row[0] name: want Alice, got %q", got)
 63→	}
 64→	if got := rows[0].Int("age"); got != 30 {
 65→		t.Errorf("row[0] age: want 30, got %d", got)
 66→	}
 67→	if got := rows[0].Float("score"); got != 9.5 {
 68→		t.Errorf("row[0] score: want 9.5, got %f", got)
 69→	}
 70→	if got := rows[1].String("name"); got != "Bob" {
 71→		t.Errorf("row[1] name: want Bob, got %q", got)
 72→	}
 73→}
 74→
 75→// 2. TSV parsing via WithDelimiter.
 76→func TestTSV(t *testing.T) {
 77→	r := mustReader(t, tsvData, WithDelimiter('\t'))
 78→	rows := collectRows(t, r)
 79→
 80→	if len(rows) != 2 {
 81→		t.Fatalf("want 2 rows, got %d", len(rows))
 82→	}
 83→	if got := rows[0].String("name"); got != "Alice" {
 84→		t.Errorf("row[0] name: want Alice, got %q", got)
 85→	}
 86→	if got := rows[0].Int("age"); got != 30 {
 87→		t.Errorf("row[0] age: want 30, got %d", got)
 88→	}
 89→	if got := rows[1].Float("score"); got != 8.1 {
 90→		t.Errorf("row[1] score: want 8.1, got %f", got)
 91→	}
 92→}
 93→
 94→// 3. Missing columns return zero/nil.
 95→func TestMissingColumn(t *testing.T) {
 96→	r := mustReader(t, csvData)
 97→	rows := collectRows(t, r)
 98→
 99→	row := rows[0]
100→
101→	if got := row.String("nonexistent"); got != "" {
102→		t.Errorf("missing String: want empty, got %q", got)
103→	}
104→	if got := row.Int("nonexistent"); got != 0 {
105→		t.Errorf("missing Int: want 0, got %d", got)
106→	}
107→	if got := row.Float("nonexistent"); got != 0 {
108→		t.Errorf("missing Float: want 0, got %f", got)
109→	}
110→	if got := row.OptionalString("nonexistent"); got != nil {
111→		t.Errorf("missing OptionalString: want nil, got %v", got)
112→	}
113→	if got := row.OptionalInt("nonexistent"); got != nil {
114→		t.Errorf("missing OptionalInt: want nil, got %v", got)
115→	}
116→	if got := row.OptionalFloat("nonexistent"); got != nil {
117→		t.Errorf("missing OptionalFloat: want nil, got %v", got)
118→	}
119→}
120→
121→// 4. Type coercion — Int and Float parse correctly.
122→func TestTypeCoercion(t *testing.T) {
123→	r := mustReader(t, csvData)
124→	rows := collectRows(t, r)
125→
126→	// row[0]: age=30, score=9.5
127→	if got := rows[0].Int("age"); got != 30 {
128→		t.Errorf("Int coercion: want 30, got %d", got)
129→	}
130→	if got := rows[0].Float("score"); got != 9.5 {
131→		t.Errorf("Float coercion: want 9.5, got %f", got)
132→	}
133→	// row[2]: age=0 (explicit zero), score="" (empty → 0)
134→	if got := rows[2].Int("age"); got != 0 {
135→		t.Errorf("Int zero: want 0, got %d", got)
136→	}
137→	if got := rows[2].Float("score"); got != 0 {
138→		t.Errorf("Float empty: want 0, got %f", got)
139→	}
140→}
141→
142→// 5. Quoted values with embedded commas and newlines.
143→func TestQuotedValues(t *testing.T) {
144→	r := mustReader(t, quotedCSV)
145→	rows := collectRows(t, r)
146→
147→	if len(rows) != 3 {
148→		t.Fatalf("want 3 rows, got %d", len(rows))
149→	}
150→	if got := rows[0].String("description"); got != "tall, blonde, and smart" {
151→		t.Errorf("quoted comma: got %q", got)
152→	}
153→	if got := rows[1].String("description"); got != `says "hello" often` {
154→		t.Errorf("quoted double-quote: got %q", got)
155→	}
156→	if got := rows[2].String("description"); got != "line1\nline2" {
157→		t.Errorf("quoted newline: got %q", got)
158→	}
159→}
160→
161→// 6. LazyQuotes handles malformed (bare) quotes.
162→func TestLazyQuotes(t *testing.T) {
163→	data := "name,note\nAlice,she said \"hello\"\nBob,fine\n"
164→	r := mustReader(t, data, WithLazyQuotes(true))
165→	rows := collectRows(t, r)
166→
167→	if len(rows) != 2 {
168→		t.Fatalf("want 2 rows, got %d", len(rows))
169→	}
170→	if got := rows[0].String("name"); got != "Alice" {
171→		t.Errorf("lazy quote row name: got %q", got)
172→	}
173→}
174→
175→// 7. Optional accessors return nil for empty cells and missing columns.
176→func TestOptionalEmptyFields(t *testing.T) {
177→	r := mustReader(t, csvData)
178→	rows := collectRows(t, r)
179→
180→	// row[1]: city="" (empty)
181→	if got := rows[1].OptionalString("city"); got != nil {
182→		t.Errorf("empty OptionalString: want nil, got %v", *got)
183→	}
184→	// row[2]: score="" (empty)
185→	if got := rows[2].OptionalFloat("score"); got != nil {
186→		t.Errorf("empty OptionalFloat: want nil, got %v", *got)
187→	}
188→	// Non-empty value should not be nil.
189→	if got := rows[0].OptionalString("name"); got == nil || *got != "Alice" {
190→		t.Errorf("non-empty OptionalString: want Alice, got %v", got)
191→	}
192→	if got := rows[0].OptionalInt("age"); got == nil || *got != 30 {
193→		t.Errorf("non-empty OptionalInt: want 30, got %v", got)
194→	}
195→	if got := rows[0].OptionalFloat("score"); got == nil || *got != 9.5 {
196→		t.Errorf("non-empty OptionalFloat: want 9.5, got %v", got)
197→	}
198→}
199→
200→// 8. EOF: Next returns false, nil at end of file.
201→func TestEOF(t *testing.T) {
202→	const single = "name,age\nAlice,30\n"
203→	r := mustReader(t, single)
204→
205→	_, ok, err := r.Next()
206→	if err != nil || !ok {
207→		t.Fatalf("first Next: ok=%v err=%v", ok, err)
208→	}
209→	_, ok, err = r.Next()
210→	if err != nil {
211→		t.Fatalf("EOF Next returned error: %v", err)
212→	}
213→	if ok {
214→		t.Error("EOF Next: want ok=false")
215→	}
216→}
217→
218→// 9. Header-only file: Next immediately returns false.
219→func TestHeaderOnly(t *testing.T) {
220→	r := mustReader(t, headerOnlyCSV)
221→	_, ok, err := r.Next()
222→	if err != nil {
223→		t.Fatalf("header-only Next: %v", err)
224→	}
225→	if ok {
226→		t.Error("header-only: want ok=false on first Next")
227→	}
228→}
229→
230→// 10. NewReader returns error on bad header read.
231→func TestNewReaderError(t *testing.T) {
232→	// An empty reader has no header line → should error.
233→	_, err := NewReader(strings.NewReader(""))
234→	if err == nil {
235→		t.Error("empty input: want error from NewReader, got nil")
236→	}
237→}
