129→func TestBuildOpinionData(t *testing.T) {
130→	tests := []struct {
131→		name string
132→		op   Opinion
133→		want map[string]any
134→	}{
135→		{
136→			name: "rank",
137→			op:   Opinion{Method: "rank", Rank: 15},
138→			want: map[string]any{"method": "rank", "rank": 15},
139→		},
140→		{
141→			name: "score",
142→			op:   Opinion{Method: "score", Score: 78.5},
143→			want: map[string]any{"method": "score", "score": 78.5},
144→		},
145→		{
146→			name: "tier",
147→			op:   Opinion{Method: "tier", Tier: "Tier 1"},
148→			want: map[string]any{"method": "tier", "tier": "Tier 1"},
149→		},
150→		{
151→			name: "range",
152→			op:   Opinion{Method: "range", Rank: 250, Tier: "201-300"},
153→			want: map[string]any{"method": "range", "rank": 250, "tier": "201-300"},
154→		},
155→	}
156→
157→	for _, tt := range tests {
158→		t.Run(tt.name, func(t *testing.T) {
159→			got := buildOpinionData(tt.op)
160→
161→			// Compare via JSON round-trip to handle int/float type differences.
162→			gotJSON, _ := json.Marshal(got)
163→			wantJSON, _ := json.Marshal(tt.want)
164→
165→			var gotMap, wantMap map[string]any
166→			json.Unmarshal(gotJSON, &gotMap)
167→			json.Unmarshal(wantJSON, &wantMap)
168→
169→			if len(gotMap) != len(wantMap) {
170→				t.Fatalf("key count: got %d, want %d\ngot:  %s\nwant: %s", len(gotMap), len(wantMap), gotJSON, wantJSON)
171→			}
172→			for k, wv := range wantMap {
173→				gv, ok := gotMap[k]
174→				if !ok {
175→					t.Errorf("missing key %q", k)
176→					continue
177→				}
178→				if jsonStr(gv) != jsonStr(wv) {
179→					t.Errorf("key %q: got %v, want %v", k, gv, wv)
180→				}
181→			}
182→		})
183→	}
184→}
185→
186→// jsonStr formats a value for comparison — handles json.Number differences.
187→func jsonStr(v any) string {
188→	b, _ := json.Marshal(v)
189→	return string(b)
190→}
