// newTestMatcher builds a Matcher without a database for unit testing.
func newTestMatcher() *Matcher {
	return &Matcher{
		exact: map[string]string{
			"harvard university":                        "166027",
			"arizona state university-tempe":            "104151",
			"ohio state university-main campus":         "204796",
			"purdue university-main campus":             "243780",
			"university of michigan-ann arbor":          "170976",
			"university of illinois urbana-champaign":   "145637",
		},
		normalized: map[string]string{
			"harvard university":                        "166027",
			"arizona state university tempe":            "104151",
			"ohio state university main campus":         "204796",
			"purdue university main campus":             "243780",
			"university of michigan ann arbor":          "170976",
			"university of illinois urbana champaign":   "145637",
			// Extra normalized variant for St. John's
			"st johns university":                       "194091",
		},
		alias: map[string]string{
			"harvard":        "166027",
			"the ohio state": "204796",
		},
		ope6: map[string]string{
			"001082": "166027",
			"001083": "104151",
		},
		ope8: map[string]string{
			"00108200": "166027",
			"00108300": "104151",
		},
	}
}

func TestMatcherMatch_Exact(t *testing.T) {
	m := newTestMatcher()

	uid, ok := m.Match("Harvard University")
	if !ok {
		t.Fatal("expected match for 'Harvard University'")
	}
	if uid != "166027" {
		t.Errorf("got unit_id %q, want %q", uid, "166027")
	}
}

func TestMatcherMatch_ExactCaseInsensitive(t *testing.T) {
	m := newTestMatcher()

	uid, ok := m.Match("HARVARD UNIVERSITY")
	if !ok {
		t.Fatal("expected case-insensitive match")
	}
	if uid != "166027" {
		t.Errorf("got unit_id %q, want %q", uid, "166027")
	}
}

func TestMatcherMatch_Normalized(t *testing.T) {
	m := newTestMatcher()

	// Punctuation stripped: "St. John's" → "st johns university"
	uid, ok := m.Match("St. John's University")
	if !ok {
		t.Fatal("expected normalized match for 'St. John's University'")
	}
	if uid != "194091" {
		t.Errorf("got unit_id %q, want %q", uid, "194091")
	}
}

func TestMatcherMatch_BuiltinAlias(t *testing.T) {
	m := newTestMatcher()

	// "penn state" → builtin alias → "pennsylvania state university main campus"
	// Not in test maps, should miss. But "arizona state university" IS covered.
	uid, ok := m.Match("Arizona State University")
	if !ok {
		t.Fatal("expected builtin alias match for 'Arizona State University'")
	}
	if uid != "104151" {
		t.Errorf("got unit_id %q, want %q", uid, "104151")
	}
}

